import hashlib
import uuid
from datetime import datetime
from collections import defaultdict

class UserInteractionTracker:
    def __init__(self):
        self.interactions = defaultdict(list)
        self.user_data = {}

    def track_interaction(self, user_id, interaction_type, data):
        anonymized_user_id = self._anonymize_user_id(user_id)
        interaction = {
            'id': str(uuid.uuid4()),
            'type': interaction_type,
            'data': data,
            'timestamp': datetime.now()
        }
        self.interactions[anonymized_user_id].append(interaction)

    def get_user_interactions(self, user_id):
        anonymized_user_id = self._anonymize_user_id(user_id)
        return self.interactions[anonymized_user_id]

    def get_all_interactions(self):
        return [interaction for interactions in self.interactions.values() for interaction in interactions]

    def _anonymize_user_id(self, user_id):
        if user_id not in self.user_data:
            self.user_data[user_id] = hashlib.sha256(str(user_id).encode()).hexdigest()
        return self.user_data[user_id]

