from datetime import datetime
from typing import Dict, List, Tuple

class Interaction:
    """Represents a user interaction on the website."""
    def __init__(self, user_id: str, interaction_type: str, value: str, timestamp: datetime):
        self.user_id = self._hash_user_id(user_id)
        self.interaction_type = interaction_type
        self.value = value
        self.timestamp = timestamp

    @staticmethod
    def _hash_user_id(user_id: str) -> str:
        """Hash the user ID to protect privacy."""
        return hashlib.sha256(user_id.encode()).hexdigest()

class InteractionManager:
    """Manages user interactions on the website."""
    def __init__(self):
        self.interactions: Dict[str, List[Interaction]] = {}

    def log_interaction(self, user_id: str, interaction_type: str, value: str) -> None:
        """Log a user interaction."""
        interaction = Interaction(user_id, interaction_type, value, datetime.now())
        if interaction.user_id not in self.interactions:
            self.interactions[interaction.user_id] = []
        self.interactions[interaction.user_id].append(interaction)

    def get_user_interactions(self, user_id: str) -> List[Interaction]:
        """Get all interactions for a user."""
        if user_id in self.interactions:
            return self.interactions[user_id]
        return []

    def get_all_interactions(self) -> List[Interaction]:
        """Get all interactions in the system."""
        interactions = []
        for user_id in self.interactions:
            interactions.extend(self.interactions[user_id])
        return interactions

    def get_interactions_by_type(self, interaction_type: str) -> List[Interaction]:
        """Get all interactions of a specific type."""
        interactions = []
        for user_id in self.interactions:
            for interaction in self.interactions[user_id]:
                if interaction.interaction_type == interaction_type:
                    interactions.append(interaction)
        return interactions

    def get_user_interactions_by_type(self, user_id: str, interaction_type: str) -> List[Interaction]:
        """Get all interactions of a specific type for a user."""
        if user_id in self.interactions:
            return [interaction for interaction in self.interactions[user_id] if interaction.interaction_type == interaction_type]
        return []

    def get_top_interactions_by_type(self, interaction_type: str, limit: int) -> List[Tuple[str, int]]:
        """Get the top interactions of a specific type."""
        interaction_counts = {}
        for user_id in self.interactions:
            for interaction in self.interactions[user_id]:
                if interaction.interaction_type == interaction_type:
                    if user_id not in interaction_counts:
                        interaction_counts[user_id] = 0
                    interaction_counts[user_id] += 1
        return sorted(interaction_counts.items(), key=lambda x: x[1], reverse=True)[:limit]

