class UserInteractionTracker:
    def __init__(self):
        self.interaction_types = ['like', 'rating', 'upload', 'settings_change']
        self.user_interactions = defaultdict(lambda: {x: [] for x in self.interaction_types})

    def track_interaction(self, user_id, interaction_type, data):
        if interaction_type not in self.interaction_types:
            raise ValueError(f"Invalid interaction type: {interaction_type}")

        hashed_user_id = self._hash_user_id(user_id)
        interaction_data = {
            'timestamp': datetime.now().isoformat(),
            'data': self._anonymize_data(data)
        }
        self.user_interactions[hashed_user_id][interaction_type].append(interaction_data)

    def get_user_interactions(self, user_id):
        hashed_user_id = self._hash_user_id(user_id)
        return self.user_interactions[hashed_user_id]

    def _hash_user_id(self, user_id):
        return sha256(user_id.encode()).hexdigest()

    def _anonymize_data(self, data):
        if isinstance(data, dict):
            return {k: self._anonymize_data(v) for k, v in data.items()}
        elif isinstance(data, list):
            return [self._anonymize_data(item) for item in data]
        elif isinstance(data, str):
            return sha256(data.encode()).hexdigest()
        else:
            return data

