from abc import ABC, abstractmethod
from typing import Dict, List
from hashlib import sha256

class Interaction(ABC):
    """Abstract base class for user interactions"""

    @abstractmethod
    def to_dict(self) -> Dict:
        """Returns a dictionary representation of the interaction"""
        pass

class Like(Interaction):
    """Represents a user 'like' interaction"""

    def __init__(self, user_id: str, item_id: str, timestamp: datetime):
        self.user_id = sha256(user_id.encode()).hexdigest()
        self.item_id = sha256(item_id.encode()).hexdigest()
        self.timestamp = timestamp

    def to_dict(self) -> Dict:
        return {
            'type': 'like',
            'user_id': self.user_id,
            'item_id': self.item_id,
            'timestamp': self.timestamp.isoformat()
        }

class Rating(Interaction):
    """Represents a user rating interaction"""

    def __init__(self, user_id: str, item_id: str, rating: float, timestamp: datetime):
        self.user_id = sha256(user_id.encode()).hexdigest()
        self.item_id = sha256(item_id.encode()).hexdigest()
        self.rating = rating
        self.timestamp = timestamp

    def to_dict(self) -> Dict:
        return {
            'type': 'rating',
            'user_id': self.user_id,
            'item_id': self.item_id,
            'rating': self.rating,
            'timestamp': self.timestamp.isoformat()
        }

class Upload(Interaction):
    """Represents a user upload interaction"""

    def __init__(self, user_id: str, item_id: str, timestamp: datetime):
        self.user_id = sha256(user_id.encode()).hexdigest()
        self.item_id = sha256(item_id.encode()).hexdigest()
        self.timestamp = timestamp

    def to_dict(self) -> Dict:
        return {
            'type': 'upload',
            'user_id': self.user_id,
            'item_id': self.item_id,
            'timestamp': self.timestamp.isoformat()
        }

class SettingsChange(Interaction):
    """Represents a user settings change interaction"""

    def __init__(self, user_id: str, setting: str, new_value: str, timestamp: datetime):
        self.user_id = sha256(user_id.encode()).hexdigest()
        self.setting = setting
        self.new_value = new_value
        self.timestamp = timestamp

    def to_dict(self) -> Dict:
