    """Tracks user interactions across a website"""

    def __init__(self):
        self.interactions: Dict[str, List[Interaction]] = {}

    def track_interaction(self, interaction: Interaction):
        """Tracks a user interaction"""
        user_id = interaction.user_id
        if user_id not in self.interactions:
            self.interactions[user_id] = []
        self.interactions[user_id].append(interaction)

    def get_user_interactions(self, user_id: str) -> List[Dict]:
        """Returns a list of all interactions for a given user"""
        if user_id not in self.interactions:
            return []
        return [interaction.to_dict() for interaction in self.interactions[user_id]]

    def get_all_interactions(self) -> List[Dict]:
        """Returns a list of all interactions across all users"""
        interactions = []
        for user_interactions in self.interactions.values():
            interactions.extend([interaction.to_dict() for interaction in user_interactions])
