from datetime import datetime
from typing import Dict, List, Tuple

class Interaction:
    def __init__(self, user_id: str, interaction_type: str, interaction_data: dict):
        self.user_id = user_id
        self.interaction_type = interaction_type
        self.interaction_data = interaction_data
        self.timestamp = datetime.now()
        self.interaction_id = str(uuid.uuid4())

    def __str__(self):
        return f"Interaction(user_id={self.user_id}, interaction_type={self.interaction_type}, interaction_data={self.interaction_data}, timestamp={self.timestamp}, interaction_id={self.interaction_id})"

class InteractionTracker:
    def __init__(self):
        self.interactions: Dict[str, List[Interaction]] = {}

    def track_interaction(self, user_id: str, interaction_type: str, interaction_data: dict):
        interaction = Interaction(user_id, interaction_type, interaction_data)
        if user_id not in self.interactions:
            self.interactions[user_id] = []
        self.interactions[user_id].append(interaction)

    def get_user_interactions(self, user_id: str) -> List[Interaction]:
        if user_id in self.interactions:
            return self.interactions[user_id]
        else:
            return []

    def get_all_interactions(self) -> List[Interaction]:
        interactions = []
        for user_id in self.interactions:
            interactions.extend(self.interactions[user_id])
        return interactions

    def get_interaction_by_id(self, interaction_id: str) -> Interaction:
        for user_id in self.interactions:
            for interaction in self.interactions[user_id]:
                if interaction.interaction_id == interaction_id:
                    return interaction
        raise ValueError(f"Interaction with ID {interaction_id} not found.")

    def anonymize_data(self) -> Tuple[Dict[str, str], Dict[str, List[Interaction]]]:
        anonymized_users = {}
        anonymized_interactions = {}
        for user_id in self.interactions:
            anonymized_user_id = hashlib.sha256(user_id.encode()).hexdigest()
            anonymized_users[anonymized_user_id] = user_id
            anonymized_interactions[anonymized_user_id] = self.interactions[user_id]
        return anonymized_users, anonymized_interactions

